INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5457444','Любов сильніша','Музика: ENLEO Слова: ENLEO. Виконує: ENLEO, МАША КОНДРАТЕНКО','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Що ти відчуваєш,
Коли навколо квітів поле,
Що зійшло у крові
Що би ти відчула,
Якщо би море потопило
Твого кращого друга?..
Як нам далі жити,
Коли наші старі малюнки
В завалах догоріли?..
Як знайти дорогу
І повернути всіх додому?..

Приспів:
Тож лий дощем із каменів і куль,
Забирай мої крила,
Автоматами мене не вб''ють,
Бо любов сильніша!
Лий дощем із каменів і куль,
Забирай мої крила,
Автомати знають, любов сильніша!

Хто ці люди за стіною?
Чому радіють, що вони
Завдали стільки болю?
Здавалось світ змінився,
Та твої сльози розказали,
Що я помилився...
І синєє небо - тепер чорний дим,
Панельні руїни це наш спільний дім,
Переламані долі заплелись у вінок,
І більше не зламаються, ніколи знов!

Приспів.

Лий дощем із каменів і куль,
Забирай мої крила,
Автомати знають,
Автомати знають,
Автомати знають, любов сильніша!
Що ти відчуваєш?..','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5457444'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5457444','Любов сильніша','Що ти відчуваєш,
Коли навколо квітів поле,
Що зійшло у крові
Що би ти відчула,
Якщо би море потопило
Твого кращого друга?..
Як нам далі жити,
Коли наші старі малюнки
В завалах догоріли?..
Як знайти дорогу
І повернути всіх додому?..

Приспів:
Тож лий дощем із каменів і куль,
Забирай мої крила,
Автоматами мене не вб''ють,
Бо любов сильніша!
Лий дощем із каменів і куль,
Забирай мої крила,
Автомати знають, любов сильніша!

Хто ці люди за стіною?
Чому радіють, що вони
Завдали стільки болю?
Здавалось світ змінився,
Та твої сльози розказали,
Що я помилився...
І синєє небо - тепер чорний дим,
Панельні руїни це наш спільний дім,
Переламані долі заплелись у вінок,
І більше не зламаються, ніколи знов!

Приспів.

Лий дощем із каменів і куль,
Забирай мої крила,
Автомати знають,
Автомати знають,
Автомати знають, любов сильніша!
Що ти відчуваєш?..');
