INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5458601','Сила кохання','Музика: Володимир Гуменчук Слова: Володимир Гуменчук, Тетяна Доканіна. Виконує: Катерина Бужинська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Як ти, мій Сокіл? Я знаю, що важко...
Ще зовсім недавно ми вірили в казку.
Ми високо в небі літали на крилах
Та клята війна нас розлучила...

Приспів:
Я Янголом білим до тебе полину...
Я серце твоє від кулі закрию!..
Усі твої рани цілунком загою!..
Я Янголом білим буду з тобою!..

Тримайся, коханий! Тримайся, герою!
Хай буде міцною і воля, і зброя!
А я щохвилини молитиму Бога -
І буде дарунком для нас перемога!

Приспів.

Я вірю ти сильний! Ти все подолаєш!
Ти наше кохання оберігаєш!
І ми в цій війні не здамося без бою!
Бо Я в твоїм серці, навіки з тобою!

Приспів.

Я янголом білим до тебе полину,
Щоб більше ніколи ти мене не покинув!
Своїми крилами тебе обіймаю!
Хай сила кохання тебе захищає!
Хай сила кохання тебе захищає!','[''pisni.org.ua'', ''cat:ato'', ''cat:devoted'', ''cat:viyskovi'', ''Пісні російсько-української війни та АТО'', ''Пісні присвячені окремим особам'', ''Пісні на військову тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5458601'), datetime('now')),datetime('now'));
