INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5461003','Мила','Музика: Golubenko, Clonnex Слова: Golubenko, Clonnex','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я ніби знайшов і знову загубив
Те почуття, коли тебе любив...
Здавалося — просто слова,
Та після тих слів ти одна...
Знаю, пам''ятаєш теплий вечір,
Останній букет,
Я — твоя погана звичка,
І це більше не секрет...
Можеш не казати, як ти погано спала,
Я хочу, щоб ти знала:

Приспів:
Мила, я знаю, ти не винна,
Ти так сильно любила, |
Але переміг страх!.. (4)

У мому Double Cupі змішана любов,
Я знаю, ти зі мною, навіть, коли не разом.
Все так змішалося, не розумію вже, де сон,
Як Guccі, Louіs, Prada, ти ніби новий сезон.
Я потрачу на тебе весь cash,
Ти така одна, таких більше не знайдеш!
Ага, парфюми Hermes, камні VVS, vіvіenne west.
World мій крутиться, бо мені стало сумно,
Давай не будем грубими — у нас не сумо...
Танцюй так, ніби це твої останні рухи...
Я заберу усю твою біль, я, ніби препарат,
Ти - той самий ключ, шо я шукав і це не дублікат.
А пам''ятаєш наші фотки із тегою ретріка,
Життя летить так швидко, забуваю все, шо опікав...

Приспів.

Послухай, моя

Приспів.

Послухай моя

Приспів. (2)','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5461003'), datetime('now')),datetime('now'));
