INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_546106','Чоловіче добрий','Музика: о. В. Стех Слова: о. В. Стех','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Чоловіче добрий,
