INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5464900','Народна','Музика: Люся Кава Слова: Люся Кава. Виконує: Люся Кава','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми всі - одна родина!
Ми всі - одна країна!
Від батька і до сина,
Славимо її!
Біда нас не зламала!
Вона нас об''єднала!
Віра нас захищала
На всі роки!

