INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5465807','Миколай у кожушку','Музика: Олена Мачайло Слова: Зоряна Лісевич','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ти був чемним чи  нечемним?
Ану пригадай!
Бо вже скоро з хмар на землю
Прийде Миколай!
Якщо слухав маму й тата
І їм помагав,
Подарунок будеш мати,
Як і замовляв!
Миколай у кожушку       |
Спакував прикольне все, |
Чемним дітям у мішку    |
Подаруночки несе!       | (2)

Ти був чемним чи  нечемним?
Ану пригадай!
Бо вже скоро з хмар на землю
Прийде Миколай!
Якщо був ти хіліганом,
Не слухав батьків,
Подарунка не дістанеш,
Якого хотів!
Миколай у кожушку       |
Бородою трясе,          |
Нечемнюхам у мішку      |
Дірку з бублика несе!   | (2)

Дірку!

Як хмаринка затанцює,
Посипле сніжок,
Чобітки Святий узує,
Вбере кожушок.
На плече собі закине
Великий мішок
З подарунками смачними
Для діточок!
Миколай у кожушку
Спакував прикольне все,
Чемним дітям у мішку
Подаруночки несе!
Миколай у кожушку
Бородою трясе,
Нечемнюхам у мішку
Дірку з бублика несе!
Дірку!','[''pisni.org.ua'', ''cat:svyatyy-mykolay'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5465807'), datetime('now')),datetime('now'));
