INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5466747','Ой, там за морями високії гори','Українська народна пісня','uk','ukraine_1991',NULL,'2007','https://drevo.etnoua.info/vse/oy-tam-za-moryamy/','Полтавська обл., Пирятинський р-н, с. Крячківка (2007 р.). Пісню виконує гурт "Древо".','Ой, там за морями високії гори
Туманом повиті,
Ой, там за лісами широкеє поле
Чорні галки вкрили...

Ой, ви, галки, галки, ви, чубарки,
Підніміться вгору,
Ой, ви, хлопці, хлопці-запорожці,
Верніться додому!

Ой, раді б ми й угору підняться -
Туман налягає,
Ой, раді б ми додому вернуться -
Султан не пускає.

Ой, не так султан,
Султан той проклятий,
Як султана мати,
Хоче нами, нами, козаками,
Турка звоювати.

Вона ж нами, нами, козаками,
Турка не звоює,
Вона нами, нашими тілами
Орлів нагодує...','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5466747'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5466747','Ой, там за морями високії гори','Ой, там за морями високії гори
Туманом повиті,
Ой, там за лісами широкеє поле
