INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5465848','Бавовнятко','Музика: Назар Савко Слова: Назар Савко. Виконує: Назар Савко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ішло Бавовнятко і зробило хлоп!
Ішло Бавовнятко і зробило хлоп!
І зробило хлоп! І зробило хлоп!
Ішло Бавовнятко і зробило хлоп!

Зайшло Бавовнятко на кримський місток,
Зайшло Бавовнятко на кримський місток,
І зробивсь хлопок! І зробивсь хлопок!
Зайшло Бавовнятко на кримський місток!

Бачить бавовнятко сірий літачок,
Що кида ракети в мирних діточок.
І зробило хлоп! І зробило хлоп!
Більше не кида ракети сірий літачок!

Щось пливе вороже, видно перископ,
На підводну лодку бавовнятко скок,
І зробило хлоп! І зробило хлоп!
Зараз, любі дітки, зробимо хіп хоп!
Один! Два! Три! Почали!

Бавовнятко! Бавовнятко!
Тут і мама! Тут і татко!
Разом зробимо ми шум,
Дивовижний супер БУМ!

Бавовнятко! Бавовнятко!
Ось і мама! Ось і татко!
Разом зробимо ми шум,
Дивовижний супер БУМ!

Ішло Бавовнятко і зробило хлоп!
Ішло Бавовнятко і зробило хлоп!
І зробило хлоп! І зробило хлоп!
Ішло Бавовнятко і зробило хлоп!','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5465848'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5465848','Бавовнятко','Ішло Бавовнятко і зробило хлоп!
