INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5469444','Холодна весна','Музика: Golubenko Слова: Golubenko, YAKTAK','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Холодна ця весна,           |
Коли пусті серця...         |
Коли твої слова             |
Лишились на вустах...       | (2)

Пам''ятатиму я твої губи,    |
Без тебе пусто там, де люди |
І не втекти мені нікуди,    |
Я бачу очі твої всюди...    | (2)

Десь там близько до води,   |
Ти далеко не ходи,          |
Там блукають наші сни,      |
Запитають: Ти куди?         | (2)

Приспів.

Холодна ця весна,
Коли пусті серця...
Коли твої слова...

Знову сонце встає під нашу розмову,
Ми ночі заспіваєм колискову...
В нашій історії поставлю кому,
Знаю, ти ще напишеш нову!
Старий місяць - половина мого серця,
Ти покинула його, але розмалювала дверця...
Високо літаєш, то не забудь парашут ти
Ну, як мені тебе забути?..
Ну, як мені тебе?..

Приспів.','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5469444'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5469444','Холодна весна','Приспів:
