INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5474545','Сила роду','Музика: Ярослава Хома (SLAVIA) Слова: Ярослава Хома (SLAVIA). Виконує: SLAVIA','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Від матері до доні,
Від батька і до сина
Воля росте у лоні
І множить нашу силу!
Квітуча і зерниста
Свята земля нам родить!
Ми всі - одне намисто,
І чорнобривці сходять!
І чорнобривці сходять!

Козаки нівроку -
Міць мого народу -
Боряться з пітьмою
За нашу свободу!
А як зійде сонце,
Заспіваєм оду!
Ми не ликом шиті,
З нами сила роду!
З нами сила роду!

Приспів.

Лину я душею
До рідного краю,
Де би не бувала
Кращого немає!
Вишита сорочка -
Щит мого народу!
Знає син і дочка:
З нами сила роду!
З нами сила роду!

Приспів.

Пташечко, лунає
З темряви щебет.
Ангели закрили
Крилами небо.
Рідная, лети до
Світла, на волю!
Як один, ми станем
Всі за тобою!

Приспів.','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5474545'), datetime('now')),datetime('now'));
