INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_54704','Заповіт','(Як умру, то поховайте). Музика: Гордій Гладкий, Андрій Безуглий Слова: Тарас Шевченко. Виконує: Борис Гмиря, Хор імені Григорія Верьовки, Андрій Безуглий, Іван Звенигородський, Хорея Козацька','uk','ukraine_before_1917',NULL,'1845','Пісневир. Молодіжний співаник. Львів 2001.','Це - один із гімнів українства. __________________________________ "Заповіт" - пісня пісень, що вийшла з-під пера геніального сина України Тараса Шевченка, звучить сьогодні на десятках мов народів світу. Повернімось хоч на хвилю в ті далекі роки, коли Кобзар написав своєрідний гімн визвольної боротьби українського народу....Листопад 1845р. видався мокрий, вітряний, холодний. Шевченкові ця погода дошкуляла більше, ніж іншим. Він працював тоді в Археографічній комісії і мусив весь час роз''їжджати по селах і містах, змальовувати старовинні церкви, монастирі, незвичайні будівлі. Вранці поет виїхав із села В''юнище в Андруші, в дорозі промок до нитки. Весь день його морозило, а надвечір він повернувся у В''юнише зовсім хворим. Довелося злягти в чужій хаті серед чужих людей. Думи роєм носилися в голові, просилися на папір. Хворіючи, поет написав своє посланіє "І мертвим, і живим, і ненародженим...", "Давидові псалми" і ще кілька ліричних творів. Тоді ж написано і вірш "Минають дні, минають ночі". Про хворобу поета дізнався його щирий приятель, переяславський лікар Андрій Осипович Козачковський і негайно ж перевіз Тараса Григоровича з В''юнища до себе у Переяслав. У хворого почалося двостороннє запалення легенів. В той час мало хто видужував від цієї хвороби. Це знав і лікар, знав і поет. Після 20 грудня хворому погіршало, становище його було майже безнадійним. Тарас Григорович лежав у чистій, теплій, затишній кімнаті, печально дивився на стелю і думав про свою останню годину, про долю України, про майбутнє рідного народу. В уяві виринав Дніпро, лани широкополі і села, що нагадували поетові писанку. Було боляче, що лишилися невиспіваними його думи, що гарячу, чисту, нерозтрачену любов до рідного народу доведеться забирати з собою в домовину. Ось у таку годину Шевченкові страшенно захотілося сказати народові, Україні, своїм друзям тепле щире слово, і на папері лягли рядки: "Як умру, то поховайте..." Вірш написано на Різдво 25 грудня 1845 р. Т.Г.Шевченко не знав тоді, що ця його поезія стане найпопулярнішою і найріднішою піснею, народним гімном, бойовим закликом до боротьби не тільки на його батьківщині, але й далеко за її межами. Не думав тоді автор "Кобзаря" ні про славу, ні про почесті, ні про можливу кару за свої сміливі думки. Він тільки хотів, може, в останній раз сказати народові про те, що думав, що почував. То був його заповіт. На щастя, міцний організм Шевченка переміг хворобу, і через два тижні поет вже вирушив у путь на Чернігівщину з тим же таки завданням Археографічної комісії. А "Заповіт" пішов у люди: його переписували в десятках і сотнях примірників, передавали з рук у руки, вивчали напам''ять аж поки не потрапив цей безсмертний твір на сторінки невеликої збірочки "Новые стихотворения Пушкина і Шевченки", що була надрукована у Лейпцігу в 1859 році, пізніше - у Львові (1863 р.) та Петербурзі (1867 р.). Але найбільшого поширення набуває він під час перевезення тіла Шевченка на Україну. Велика в цьому заслуга художника Г.Честахівського, який багатьох із тих, що прийшли на Чернечу гору попрощатися з Кобзарем, навчив "Заповіту". В різних списках і різних виданнях цей вірш називався: "Завіщаніє", "Заповіт", "Думка", "Остання воля". З 1867 року за ним міцно закріпилася назва "Заповіт". Уперше, 1862 року, звучав "Заповіт" польською мовою. Його переклав А.Гожалчинський, 4868 року - сербохорватською в інтерпретації А.Николина, 1869 року - російською. Переклад здійснив М.Гербель. 1870 р. в Чернівцях вийшла і набула поширення в Західній Європі книжка австрійського поета Йоганна-Георга Обріста - "Тарас Григорович Шевченко". Склали її розвідка про життя і творчість Кобзаря та німецькі переклади його найбільш політично загострених творів, у тім числі й "Заповіту". Саме це видання рекомендував зарубіжному читачеві Михайло Драгоманов у своїй праці "Українська література, заборонена російським урядом", що з''явилася друком 1878 року в Женеві французькою мовою як доповідь на Міжнародний конгрес письменників у Парижі. Українські поети сприяли поширенню революційного "Заповіту" за межами України. Іван Франко 1882 року переклав пісню німецькою мовою, а Сильвестр Калянець, живучи в далекій Бразилії, 1936 року переклав "Заповіт", як і ряд інших поезій Кобзаря, сповнених тугою за рідним краєм, - португальською мовою. В безсмертних ідеях "Заповіту", в його образах, у звучанні виразно чуємо могутні акорди революційної музики Бетховена, одного з улюблених композиторів Кобзаря. Так проступає характерна риса індивідуального стилю Шевченка-поета, художника, музично обдарованої людини й мислителя - гармонійне поєднання різних муз. "Заповіт" - це квінтесенція всієї творчості Шевченка. У ньому сфокусовано провідні ідеї, мотиви й образи гнівної музи поета-борця, Увесь твір звучить як пристрасна промова революційного трибуна, звернена до народу. В елегійно-епічному тоні засобами народної символіки малює Т.Г.Шевченко у перших строфах вірша поетичний образ України, зігрітий любов''ю. Але в наступних рядках мова його стає уривчаста, схвильована - про ворогів вітчизни поет не може говорити спокійно. Силу Шевченкового "Заповіту" одразу відчули охоронці самодержавства. Шеф жандармів і начальник третього відділу Орлов, переглядаючи рукописну збірку "Три літа" яка виявилась головною підставою для звинувачення поета й заслання - аж на десять років, з люттю перекреслив текст "Заповіту", кваліфікувавши цей твір (та деякі інші) як "в высшей степени дерзкого и возмутительного содержания". Нетлінний образ степової гори-могили великого Кобзаря став національною святинею, оспіваною самим поетом у його безсмертному "Заповіті". Друзі поета, його сучасники, народ свято виконали заповіт. З далекої північної столиці тіло довго везли на Україну, не поховали й у Києві, попливло воно переповненим у повінь Дніпром далі, у край, де високі гори-могили стоять над священною рікою. Друзі вибрали для поховання місце на Чернечій горі, звіряючи величність місця із заповітними рядками, а тендітні дівочі руки, за давнім народним звичаєм, покотили віз із важкою свинцевою труною горами й долинами у довгу останню путь. Тут, на крутій горі, над самим, Дніпром і поховали. Поставили на високій горі-могилі над Дніпром одинокий дубовий хрест. Кругом цвіли дикі рожі, згодом заколосилася тирса й сріблясті хвилі дикого степу покотилися по горі-могилі. В жодного фараона не було такої величної заквітчаної могили. В жодного правителя світу нема такої грандіозної усипальниці, якою стала над горою сама твердь небесна. Так поховав народ свого вірного сина. Цікава історія музики "Заповіту". Через сім років після смерті автора "Кобзаря" громадськість Львова збиралася вперше відзначити Шевченкові роковини великим концертом. Тоді ще майже не було пісень на слова Шевченка. Зважаючи на цю прикру обставину львів''яни звернулися до молодого київського композитора Миколи Лисенка з проханням написати музику до "Заповіту". Микола Віталійович охоче погодився виконати це прохання, напружено працював протягом тривалого часу, намагаючись поєднати дух шевченківської поезії зі специфікою української народної пісні, і напередодні сьомих роковин з дня смерті поета відіслав свій твір у Львів. Це був його перший оригінальний твір. У виконанні збірного хору львівської громади він уперше прозвучав у ювілейні шевченківські дні 1868 року. Одночасно з Миколою Лисенком написав музику до "Заповіту" й галицький композитор Михайло Вербицький, проте художній рівень його композиції був нижчий. Текст "Заповіту" в нього співає тенор, а хор підхоплює тільки одну прикінцеву строфу - "Поховайте та вставайте...". Широкого розповсюдження праця галицького композитора не здобула Із 1868 року хорові колективи виконували цю революційно-національну пісню в дуже урочистій обстановці. Причому кожний раз зал уставав під час співу, Ця традиція - слухати спів "Заповіту" стоячи - поширилася на всю Україну, а далі - і на цілу планету, де тільки живуть розсипані долею українці. У 1870 році з''явилася нова, цілком оригінальна мелодія "Заповіту", яка швидко поширилася по всій Україні і незабаром стала популярною народною піснею. Написав її скромний полтавський учитель музики Гордій Павлович Гладкий. Він народився близько 1849 року, на невеличкому хуторі нинішнього Карлівського району на Полтавщині, походив з незаможної родини, бо вже в юнацькі роки він був змушений сам заробляти собі на шматок хліба. У 60-х роках він працював продавцем у чайній крамниці, що належала московським купцям братам Поповим і знаходилась на Петровській вулиці в Полтаві. Музичні здібності у Г.Гладкого виявилися досить рано, оскільки вже під час роботи прикажчиком, він мав гарний голос. Особливо захоплювався юнак українськими народними піснями, яких знав безліч. Шевченка шанував понад усе. Не маючи більш солідного інструменту, він усі свої пісні програвав на гітарі, проспівував їх з приятелями, які були завжди бажаними гостями у його убогій хатині. Кожної суботи в кімнаті у Г.Гладкого на першому поверсі великого триповерхового будинку збиралась молодь. Це були переважно місцеві семінаристи, котрі, як правило, володіли гарними голосами і тому кожного разу експромтом утворювався першорядний чоловічий хор. Цілком природно, що цим хором завжди керував сам Г.Гладкий, який вже тоді виявляв свої неабиякі диригентські здібності. Саме цей хор став першим виконавцем його творів. Серед них було чимало хорових обробок українських народних пісень, а також власні твори на слова Т.Г.Шевченка, а також його славнозвісний "Заповіт". Незабаром Гордій Павлович довідався, що його "Заповіт" уже співають полтавські семінаристи, що й у Харківському університеті звучить його мелодія, що її знають у Києві. Твір Г.П.Гладкого дуже сподобався М.В.Лисенкові. Він зробив у ньому кілька незначних поправок, і пісня птахом крилатим полинула у великий світ. Вона переходила від покоління до покоління як дорогоцінний скарб, як велике духовне надбання українського народу. Цей "Заповіт" співаємо ми і сьогодні. Гордію Павловичу Гладкому пощастило створити хорову мелодію з величезною переконливою силою. В ній вражаюче поєднуються народний гнів до гнобителів і глибока любов до рідної України, заклик до боротьби за волю, за народне щастя і елементи ніжної лірики, яка характеризує українську природу. В музиці Г.Гладкого вдало відтворено узагальнений образ українського народу. При передруці посилатися на "Громаду"','Як умру, то поховайте
Мене на могилі,
Серед степу широкого,
На Вкраїні милій,
Щоб лани широкополі,
І Дніпро, і кручі
Було видно, було чути,
Як реве ревучий.

Як понесе з України
У синєє море
Кров ворожу... отойді я
І лани, і гори —
Все покину і полину
До самого Бога
Молитися... а до того
Я не знаю Бога.

Поховайте та вставайте,
Кайдани порвіте
І вражою злою кров''ю
Волю окропіте.
І мене в сем''ї великій,
В сем''ї вольній, новій,
Не забудьте пом''янути
Незлим тихим словом','[''pisni.org.ua'', ''cat:himny-marshi'', ''cat:patriotic'', ''Гимни та марші'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_54704'), datetime('now')),datetime('now'));
