INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5488949','Сльози Перемоги','Музика: Роксолана Калин Слова: Василь Фесюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Вітри холодні в Вкраїні віють,
Здригається від пострілів земля...
Сини і доньки знову на Вкраїні
В боях пекельних віддають життя...
О, рідна моя ненько Україно,
Чом на пороги знов прийшла біда?..
Чому на наші сонячні дороги
Ступила чорна ворога нога?..

Приспів:
Та пам''ятаймо, браття, що Вкраїна
За всі роки, за всі віки
Ніколи не ставала на коліна,
Не піднімала руки догори!..
І знаймо, любі браття, що Вкраїна
За всі роки, за всі віки
Лиш перед Господом ставала на коліна
І піднімала руки до мольби!

Єднаймось, рідні, дасть Господь нам сили!
До правдоньки завжди тернистий шлях,
Бо перемога лиш дана народу,
Який не зронить прапор у боях!
Вернімо наші всі степи козацькі,
Засіймо з миром нові врожаї!
Хай світ великий бачить Україну
З сльозами перемоги на лиці!

Приспів. (2)

Лиш перед Господом ставала на коліна
І піднімала руки до мольби!','[''pisni.org.ua'', ''cat:viyskovi'', ''cat:zahalni-cinnosti'', ''Пісні на військову тематику'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5488949'), datetime('now')),datetime('now'));
