INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5478141','Ми - Україна!','Музика: Анна Лук''янченко Слова: Анна Лук''янченко','uk','ukraine_1991',NULL,NULL,'авторське подання','Пісню виконує Анна Лук''янченко.','Повернути би все, як було раніше,
Наше мирне життя, хочу я найбільше,
Щоб наша рідна земля ніколи не страждала
І у батьківській хаті рідня чекала!
Не просили нікого ми нас визволяти,
Хіба то є спасіння у людей стріляти?..
Ми є незламним народом, у нас є сила,
І зовсім скоро країна розправить крила!

Приспів:
Ми - Україна, найкраща, єдина!
Ми є ті люди, незламна велика родина!
Я вірю, ми зможемо! Ми все переможемо!
Вперед, Україна!
За майбутнє, моя батьківщина!

У нас є діти. Вони бажають жити,
Побачити дитинство і просто любити!
Наші чоловіки боронять країну,
Спинами закривають кожну людину!
Ворожу лють, об''єднавшись, ми подолаєм!
Розквітне наша країна, ми точно знаєм!
Звільніть ви наші землі!
У нас є все для життя!
Хіба ви ще не побачили,
Ми всі - велика сім''я! Сім''я!..

Приспів.

Я вірю, ми зможемо! Ми все переможемо!
Вперед, Україна!
За майбутнє, моя батьківщина!
У нас є майбутнє - моя Україна!','[''pisni.org.ua'', ''cat:ato'', ''cat:devoted'', ''cat:patriotic'', ''cat:viyskovi'', ''Пісні російсько-української війни та АТО'', ''Пісні присвячені окремим особам'', ''Патріотичні пісні'', ''Пісні на військову тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5478141'), datetime('now')),datetime('now'));
