INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5490106','Брат','Музика: Володимир Будейчук Слова: Ірина Зінковська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Благословили нас батьки любов''ю,
Господь одну сім''ю подарував!
Дві долі, кров одна у нас з тобою,
І ми обоє віримо в дива!
Характери у нас не дуже схожі,
Та завжди ділимо усе на двох,
Коли ти поруч, кожен день погожий,
І так спокійно, світло, без тривог!

Приспів:
Мій брат - найкращий друг
І серце найвірніше!
Мій брат, твій розум
І сміливість - мій покров!
Мій брат, нема на світі
Душ від нас рідніших!
Хай завжди береже тебе моя любов!

Ти - найщиріший в світі співрозмовник,
В твоїх очах - усе моє життя...
Один ти бачив, на який жертовник
Кладу, буває, сильні почуття...
Благословили нас батьки любов''ю,
Господь одну сім''ю подарував!
Дві долі, кров одна у нас з тобою,
І ми обоє віримо в дива!

Приспів.','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5490106'), datetime('now')),datetime('now'));
