INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_549405','Моя мила шудре-дудре (2)','Українська народна пісня. Виконує: Хор "Чумаки"','uk','ukraine_1991',NULL,'1993','1. Лемківські пісні. 2. Василь Триліс (триголосся).','В репертуарі хору "Чумаки" (м. Київ) з 1993 року. Нас захопило химерне й талановите - властиво лемківське - поєднання трагічного й комічного, дотепна й глибока аргументація у вічній дискусіїї "Пити чи не пити". Не менш оригінальна та загадкова й мелодія пісні, вона дає надто багато волі для гармонізації та ритмічних вирішень...','Моя мила шудре-дудре, же я п''ю. (2)
Почкай, почкай, моя наймилійша,
Як я гмру!

Як я буду на лавонці лежати,    (2)
Хтоди будеш, моя наймилійша,
Плакати!

- Ой встань, милий, подивися, встань, серце, (2)
Нап''ємося тої горівочки,
Як перше!

Нап''ємося горівочки ще й меду. (2)
- Юж я свою буйну голівоньку
Не зведу.

Моя мила шудре-дудре, же я п''ю. (2)
Почкай, почкай, будеш банувала,
Як я гмру','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_549405'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_549405','Моя мила шудре-дудре (2)','Моя мила шудре-дудре, же я п''ю. (2)
