INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5476343','Весна','Музика: Марина Полончак Слова: Марина Полончак','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Коли калина зацвіла,
До нас постукала весна,
Дала нам крила
І з собою понесла!..
Коли прийшла до нас весна,
На серці стало так тепло,
Так добре нам
Іще з тобою не було!..

Приспів:
Яка ж була тоді весна!..
Які ж солодкі ти слова
Мені казав, коли колина цвіла!..
Калина скоро відцвіла,
Та не минула та весна!..
Для нас з тобою, милий мій,
Цвіте вона у нас в серцях!..

Від щастя кругом голова,
І буде осінь чи зима,
З тобою холоду нема,
Любов цвіте, любов жива!..
І та весна й калини цвіт,
І лиш для нас цей білий світ!
Весна в душі розтопить,
Навіть крихкий лід!..

Приспів.','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5476343'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5476343','Весна','Коли калина зацвіла,
До нас постукала весна,
Дала нам крила
І з собою понесла!..
Коли прийшла до нас весна,
На серці стало так тепло,
Так добре нам
Іще з тобою не було!..

Приспів:
Яка ж була тоді весна!..
Які ж солодкі ти слова
Мені казав, коли колина цвіла!..
Калина скоро відцвіла,
Та не минула та весна!..
Для нас з тобою, милий мій,
Цвіте вона у нас в серцях!..

Від щастя кругом голова,
І буде осінь чи зима,
З тобою холоду нема,
Любов цвіте, любов жива!..
