INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5494646','Пес','Музика: Ольга Маєвська Слова: Надія Семена','uk','ukraine_1991',NULL,NULL,'авторське подання','Пісню виконує Ольга Маєвська (альбом: Пісні для дітей).','В кожному в домі потрібен свій пес,
Знай, для господаря він — антистрес,
Він охоронець і просто дружбан,
З ним можна сісти удвох на диван.

По телевізору глянуть кіно.
Поговорити, про що — все одно,
Уважно послухає, не переб''є,
Вроджений такт у собак точно є!

Псу мало треба: лиш корм для собак,
Зранку гуляти сходити у парк,
Трішки уваги, любов, доброта,
Дружня підтримка — то справа свята!','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5494646'), datetime('now')),datetime('now'));
