INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5502106','Різдвяна','Музика: Олександр Шкуркiн, Андрій Нiколайчик Слова: Олександр Шкуркiн, Олександр Беляк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Серед зірок у небі
З''явилась ще одна -
Лежить у колисці baby,
Народження яке святкує земля!
Серед зірок
Сяє Він як сонце людям!
Це справжній Бог,
І Він назавжди з нами буде!
І Він назавжди з нами буде!

Приспів:
Знов! Знов настало Різдво!
Знов! Знов бачу Божу любов!
Знов! Знов настало Різдво!
Знов! Знов бачу Божу любов!

В дім завітала знову
Радісна новина!
Підійми руки вгору -
Цар прийшов не дарма!
Народився Христос!
Ми святкуємо Різдво!
Славлять Його всі
Країни і міста!
До людей сьогодні Бог,
Як ніколи близько!
Під частоти низькі
Лунає блага звістка:
Народився Христос!
Це подія дійсно!
Повірити в дива
Ніколи не пізно!
Зараз саме час дати
Богу перше місце!
І хай лунає людям всюди
Ця Різдвяна пісня!

Приспів. (2)

Бачу Божу любов!
Бачу Божу любов!
Бачу Божу любов!','[''pisni.org.ua'', ''cat:suchasni-pisni-rizdvo'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5502106'), datetime('now')),datetime('now'));
