INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_550040','Їхали повстанці','(Про Тилю). Музика: народна Слова: Роман Туровський-Савчук','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Їхали повстанці
З лиману до дому
Підманули Тилю -
Забрали з собою.
Ой ти, Тильо,
Тильо молодая!
Підманули Тилю -
Забрали з собою.

Годі ж тобі, Тильо,
лапсердаки шити.
Краще, дівча, з нами
старий світ палити.
Ой ти, Тильо,
Тильо молодая!
Краще, дівча, з нами
старий світ палити.

Скаче в полі Тиля,
в шкіряній тужурці
рілля під копитом,
Маузер в кобурці.
Ой ти, Тильо,
Тильо молодая!
рілля під копитом,
Маузер в кобурці.

Віє чорний вітер
Темрява застила.
У тачанці Тиля
сина народила.
Ой ти, Тильо,
Тильо молодая!
У тачанці Тиля
сина народила.

Сина народила
Нестором назвала.
Пригорнув до себе
далі поскакала.
Ой ти, Тильо,
Тильо молодая!
Пригорнув до себе
за Прут поскакала...    Мелодія','[''pisni.org.ua'', ''cat:pivden'', ''Пісні з півдня України'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_550040'), datetime('now')),datetime('now'));
