INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_549747','Дівчатко Дівчатко','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Лемківські співанки. Зібрав і упорядкував М. Соболевський. — К.: Музична Україна, 1967. — 320 с.','Пісня з добірки М.Соболевського: Лемківські співанки Діалектизми: ани - ані; вельо - багато, дуже; гардий - гарний, хороший, пристойний; горі - догори; доли - додолу; дочекам - дочекаюся; драга - дорога; єдна - одна; жена - жінка, дружина; забыв-єм - забув я; мі - мені; набоженкам - набожуся, намолюся Богу; надобна - гарна, хороша; паленочка - горілка, самогонка; пінязі - гроші; повісти - сказати; пут - шлях, путь; хлоп - мужчина, чоловік; хыжа - хата; червена - червона; што - що.','Дівчатко Дівчатко повідж мі на разі
Най мої коничкы ей не стоят на дразі

Бо мої коничкы вельо мі коштуют
Ани єдной нічки ей дома не ночуют

Ой Боже мій Боже на мою мамичку
Же мя замуж дают ей таку невеличку

Ни шити ни прясти ни хыжу замести
Корови не здою ей бо ся хвоста бою

Ой Боже мій Боже на мою мамичку
Гей же мя выдают ей таку невеличку

Ни мі серпом жати ни мі з хлопом спати
Ой Боже мій Боже што буде почати

Ой Боже мій Боже што я наробила
Коровы-м продала пінязі пропила

Ой Боже мій Боже што ся набоженкам
Коли ж я ся коли ж ей доброти дочекам

Казали мі піти з кониками на ніч
Забыв-єм повісти дівчатку добраніч

— Добра ночка добра дівчино надобна !
— І тобі ден білий мій Яничку милий !

Доли селом стежка горі селом пут-пут
Под же мій миленький ей паленочки куп-куп

А під старим дубом трава червеніє
При недобрім мужі жена постаріє

Під молодим дубом трава зеленіцька
Так при добрім мужі жена молодіцька

На високій горі там ся дівча молит
Червена як ружа о гардого мужа','[''pisni.org.ua'', ''cat:lemkivski'', ''cat:vesilni'', ''Лемківські пісні'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_549747'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_549747','Дівчатко Дівчатко','Дівчатко Дівчатко повідж мі на разі
Най мої коничкы ей не стоят на дразі

