INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5482646','Цінувати життя','Музика: KOLA Слова: KOLA','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Крихти у ліжку - неприємно,
Крихта любові -
Це для когось потреба.
Хтось плекає потаємне,
А хтось розповідає
Про життя своє щоденне...
Все так відносно в цьому світі,
Суп комусь гострий,
А комусь хоча б поїсти...
Хтось любить простір,
Хтось ходить в гості любитись,
Хтось не п''є зовсім,
А хтось так хоче напитись...

Приспів:
Ціну-цінувати, цінувати життя!..
Ціну-ціну-цінувати кожну хвилинку!..
Ціну-цінувати, цінувати тих, хто поряд,
Їде вгору - а не вийшов на зупинці!..
Ціну-цінувати, цінувати життя!..
Ціну-ціну-цінувати кожну хвилинку!..
Цінувати землю, вітер і ставки, і гори,
І тих, хто поруч, і в хаті, і надворі!..

Хтось наодинці там, де людно,
Хтось себе знову знаходить і губить...
Хтось цілує ніжно в губи,
А хтось завжди думає, що скажуть люди...
Все так відносно в цьому світі,
Хтось сидить вдома,
А в когось нема де сісти...
Всі ми з різного тіста,
Але всі носим любов, як намисто...

Приспів.

Цінуй кожну мить,
Бо мить - це і є життя!..','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5482646'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5482646','Цінувати життя','Крихти у ліжку - неприємно,
Крихта любові -
Це для когось потреба.
Хтось плекає потаємне,
А хтось розповідає
Про життя своє щоденне...
Все так відносно в цьому світі,
Суп комусь гострий,
А комусь хоча б поїсти...
Хтось любить простір,
Хтось ходить в гості любитись,
Хтось не п''є зовсім,
А хтось так хоче напитись...

Приспів:
Ціну-цінувати, цінувати життя!..
Ціну-ціну-цінувати кожну хвилинку!..
Ціну-цінувати, цінувати тих, хто поряд,
Їде вгору - а не вийшов на зупинці!..
Ціну-цінувати, цінувати життя!..
Ціну-ціну-цінувати кожну хвилинку!..
Цінувати землю, вітер і ставки, і гори,
І тих, хто поруч, і в хаті, і надворі!..

Хтось наодинці там, де людно,
Хтось себе знову знаходить і губить...
Хтось цілує ніжно в губи,
А хтось завжди думає, що скажуть люди...
Все так відносно в цьому світі,
Хтось сидить вдома,
А в когось нема де сісти...
Всі ми з різного тіста,
Але всі носим любов, як намисто...

Приспів.

Цінуй кожну мить,
Бо мить - це і є життя!..');
