INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5503949','Колір музики','Музика: Геля Зозуля','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Нові ноти,
Як новий етап,
Які ж ми ідіоти,
Що жили не так,
Як пророчили Боги...
Не по тим дорогам,
Не туди пішли,
Бо ми не слухали

Приспів:
Колір музики, її темп,
Він танцює зі мною.
Скільки тем
Ми вже обговорили,
Стільки пережили
Із музикою.
Я співаю, танцюю!..

Закреслені ноти,
На фоні дим і я...
Я не проти,
Шо ніхто не скаже:
Ти моя!
На світанку, зранку,
Вдень і вночі
Я закриваю очі і бачу

Приспів. (2)

Нові ноти,
Як новий етап,
Які ж ми ідіоти,
Що жили не так,
Як пророчили Боги...
Не по тим дорогам,
Не туди пішли,
Бо ми не слухали

Приспів. (2)

Мої сльози,
Наче морози серед зими,
Такі сумні...
Моя музика - мої ліки,
І я їх вживаю,
Наче наркотики...','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5503949'), datetime('now')),datetime('now'));
