INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5506040','Солдат','Музика: Роман Скорпіон Слова: Роман Скорпіон','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Де б ти не був далеко від дому,
Ти хоч вісточку рідним пришли.
Що живий, що все добре з тобою,
Я прошу тебе, лиш не мовчи!..
І якщо стане важко на серці,
Ти у Боги сили проси,
Бо чекають тебе вдома рідні!
Прошу тебе, солдат, живи!..

Приспів:
Солдат, ти - Герой України!
Солдат, незламна віра твоя!
Солдат, за твоєю спиною
Покоління країни!
Прошу тебе, солдат, живи!..

І нехай твоя віра
Додасть тобі сили,
Стане світлом в цій лютій пітьмі.
Не зламайтесь, титани країни,
Повертайтеся з бою живі!
І якщо стане важко на серці,
Ти у Боги сили проси,
Бо чекають тебе вдома рідні!
Прошу тебе, солдат, живи!..

Приспів.

Борітеся - поборете!
Вам Бог помагає!
За вас правда, за вас Слава
І воля святая!

Приспів.','[''pisni.org.ua'', ''cat:ato'', ''cat:zahalni-cinnosti'', ''Пісні російсько-української війни та АТО'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5506040'), datetime('now')),datetime('now'));
