INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5494003','Новий рік','Музика: Ольга Мамієнко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
На порозі Новий рік! Новий рік!
Ми запрошуємо в гості усіх!
Ми бажаємо вам щастя й добра,
Щоб щаслива ваша доля була!

Прилетіли в Україну
Заметілі й хуртовина,
Снігом замело Карпати,
Будем разом святкувати!
Загадаємо бажання:
Щастя вам усім, кохання!
За столом уся родина,
З Новим роком, Україна!

Приспів. (2)

Спить долина за лісами,
Заколисана снігами,
Світ прикрашений зірками,
Новорічними піснями!
Хай різдвяна пісня ллється,
І слова летять від серця!
Хай радіє вся родина,
З Новим роком, Україна!

Приспів. (2)','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:new-year'', ''Дитячі пісні'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5494003'), datetime('now')),datetime('now'));
