INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5494040','Новий рік у гості йде','Музика: Ольга Маєвська Слова: Ольга Маєвська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Новий рік у гості йде,
Подарунки він несе
Для маленьких, для звірят,
Для дівчаток і хлоп''ят!

Приспів:
Ой, як хороше сьогодні,
Ой, як весело всім нам,
Новорічні передзвони
Чути всюди: тут і там!
Новий рік іде до хати,
Ти скоріш його вітай!
Новорічне гарне свято
Разом з нами зустрічай!

Ми не будем нудьгувати,
Будемо ми танцювати,
Пару ми собі знайдем,
І кружляти враз почнем!

Приспів.

Ти, дружечок, зупинись,
Друзям всім ти посміхнись!
Та поплескай ти гучніше,
І потупай веселіше!

Приспів.

А тепер ми всі йдемо,
Хоровод свій ведемо,
Новий рік стрічаєм всі,
І співаємо пісні!

Приспів.

Новорічне гарне свято
Разом з нами зустрічай!','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5494040'), datetime('now')),datetime('now'));
