INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_551242','Ми українці',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ми українці, сильні духом!
Відважні й мужні юнаки,
Свого народу вірні слуги,
Землі своєї захисники.

Приспів:
Випала така нам доля,
нам такий судився шлях,
Захищати небо й поле
Синьо-жовтий стяг!

Випала така нам доля,
Щастя нам таке дано,
захищати небо й поле,
Синьо-жовте знамено!

Йдемо в колоні: три-чотири,
Під нами аж земля гуде,
Ведуть нас мужні командири,
У світі кращих нема ніде!

