INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_551209','Я з вами зустрівся так просто, спокійно','Слова: Л.Пеньковский, Анатолій Присяжнюк','uk','ukraine_1991',NULL,NULL,'Л.Пеньковский (?). "Спокойно и просто я встретился с вами". "Ці невигадливі, зворушливі слова... (переклад з рос. лірики ХІХ-ХХ ст). А.Присяжнюк','З репертуару Марии Наровской','Я з вами зустрівся так просто, спокійно,
Душа призабула вже рану надривну.
Та прірва між нами лягла безнадійно,
Ми тільки знайомі. Як дивно...

Як дивно: ще вчора горнулись безслівно,
У стрічах час плинув безмірно, чарівно,
А нині, ах, нині з вчорашнім не рівне -
Ми тільки знайомі. Як дивно...

Зав''язка - це казка. Розв''язка - боління
Та думати завжди про Нього невпинно
Не варто. А може... Даремне... Наївно.
Ми тільки знайомі. Як дивно...','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_551209'), datetime('now')),datetime('now'));
