INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5513848','Про тебе мені','Музика: Golubenko, YAKTAK Слова: Golubenko, YAKTAK','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Так інколи буває,      |
Хтось когось забуває,  |
Хтось відшукає щастя   |
У тишині...            |
І хай життя нас кидає, |
Та серце все пам''ятає, |
Воно розкаже все       |
Про тебе мені!..       | (2)

Якщо життя - пустеля для нас,
Ти - моя криниця.
Кажуть, серця холодить час,
Хочу таким лишиться!..
Якщо життя - відео в ютуб,
Ти - для мене книга,
Поруч зі мною просто побудь!
Ти будеш аркуш, а я - слова,
Буду писати сторі нашу я на бітах!
Називатиму вулиці твоїм ім''ям,
Наші моменти всі не вмістиш
В гігабайтах...
Ти будеш музика, а я - вірші,
Ти - часом рок пісні,
А я - повільні танці,
Так наші серця зимою
Не гріють станції,
Як твоє фото в телефоні
На заставці!..

Приспів.

Навіть, коли в дощах я,
Навіть, коли болить душа,
Час наче та вода,
Все зупинилось на очах...
Навіть, коли в дощах я,
Навіть, коли болить душа,
Час наче та вода,
Все відтепер в твоїх руках!..

Приспів.

Так інколи буває,
Хтось когось забуває,
Та серце все нагадає
Про тебе мені!..','[''pisni.org.ua'', ''cat:zahalni-cinnosti'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5513848'), datetime('now')),datetime('now'));
