INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5514444','Возвеселімся всі разом нині','Українська народна пісня','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'Владика Ганна с. Пнівці, Борщівського району.',NULL,'Возвеселімся всі разом нині -
Христос родився в бідній яскині!
По Україні співаймо, друзі,
Хай пісня лине в наш Київ!

Хай пісня лине в столицю Київ,
Нехай почують в Святій Софії,
Нехай здригнуться усії мури,
Нехай повстане весь народ!

Ми пам''ятаєм Базари й Крути,
Кривавий Париж і Роттердам,
Де впали вірні сини Вкраїни,
Де впали вожді Семен й Євген.

Пісню роджену співаєм нині
Братам в Сибіру і по тюрмах,
Що терплять муки за ідею -
За Самостійну Україну!..','[''pisni.org.ua'', ''cat:strilecki'', ''Стрілецькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5514444'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5514444','Возвеселімся всі разом нині','Возвеселімся всі разом нині -
Христос родився в бідній яскині!
По Україні співаймо, друзі,
Хай пісня лине в наш Київ!

Хай пісня лине в столицю Київ,
Нехай почують в Святій Софії,
Нехай здригнуться усії мури,
Нехай повстане весь народ!

Ми пам''ятаєм Базари й Крути,
Кривавий Париж і Роттердам,
Де впали вірні сини Вкраїни,
Де впали вожді Семен й Євген.

Пісню роджену співаєм нині
Братам в Сибіру і по тюрмах,
Що терплять муки за ідею -
За Самостійну Україну!..');
