INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5524900','Ой, на горі та женці жнуть','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1935','аудіозапис','с. Кам''янка, Черкаська область. Пісню виконують колгоспницi (Я. Гирющенко, О. Засядько, М. Коновал, Н. Бур''ян), запис 1935 року.','Ой, на горі та(м) женці жнуть,
