INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5530040','Вижити до ранку','Музика: Сергій Соловій Слова: Юрій Федоренко, Сергій Соловій','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Нам треба побороти цю пітьму
І вижити до ранку,
А там прийдуть, а там прийдуть
Нас поміняти на світанку!..

Нам треба побороти цю пітьму,
Напитися серпанком,
І впасти в ранішню росу,
Туман вдихати, мов цигарку...

Нам треба побороти цю пітьму,
Почути ранню пташку,
Співати з нею пісню цю,
Щоб, як натягнута струна,
Боліли зв''язки!..

Нам треба побороти цю пітьму! -
Повторюю слова ці, наче мантру.
Воскреснуть всі міста,
Що стратила війна,
Нам просто треба вижити до ранку!

Воскреснуть всі міста,
Що стратила війна,
Нам просто треба вижити до ранку!
Нам просто треба вижити до ранку!
Нам треба вижити до ранку!

Ми побороли цю страшну чуму,
Хоч часом було важко,
Ми боремось, а значить - ми живі!
Нам просто треба вижити до ранку!

Ми боремось, а значить - ми живі!
Нам просто треба вижити до ранку!
