INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5529444','Пісня про Оксану','Музика: Юліян Китастий','uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис',NULL,'За рікою постріли в туманах,
І по селах згашено вогні,
Дмуть вітри із півночі, Оксано, |
В нашій неспокійній стороні...  | (2)

Що ми знали й бачили з тобою,
І страшить майбутнє, наче ніч...
Ось полинуть літа за водою,
І не буде більше теплих стріч...

А як осінь в вирій птиць поманить,
Неодмінно я вернусь назад!..
Тільки ти не вийдеш в ніч багряну
В задрімалий, опустілий сад...

Стрілянина розпочалась з шанців,
Зіллям і травою обросли...
Йшли в розвідку вечором повстанці
І тебе, розстріляну, знайшли...

В нашім краю осінь у туманах,
Від набоїв рвуться береги...
Чуєш, нарід наш встає, Оксано?  |
І тремтять, тікають вороги!..   | (2)','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5529444'), datetime('now')),datetime('now'));
