INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5498848','Розраховуй на мене','Музика: Андрій Вдовиченко (DOVI) Слова: Катерина Медведєва, Іван Клименко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'У самого, друже, бувало, й немало,
Коли з рук все падає низько.
Не страшись, відпустити кермо, я тримаю,
Пересядь-но ти на пасажирське.
Поміж "можу" і "допоможу" є різниця,
Чекаю тебе я на розі, бо відверті
Розмови не встигають до місця
Й народжуються в дорозі.

Приспів:
Розраховуй, друже, на мене!
Розраховуй в тяжку годину!
Набирай, коли в думках сумне!
Я не лишу в біді, не покину!

У самого, друже, лишилась позаду
Поразок і спогадів низка,
Неприємні деталі трапляються й далі -
То пусте все, коли друзі близько!
І на нашій потертій контурній карті
Ми взяли і стерли кордони,
Не вагайся ніколи-ніколи набрати
Цифри мого телефону!

Приспів. (2)

Розраховуй в тяжку годину!
Я не лишу в біді, не покину!','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5498848'), datetime('now')),datetime('now'));
