INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_551508','Нині радість стала','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Нині радість стала,
Яка не бувала,
Над вертепом зірка ясна
Світу засіяла

Там Христос родився,
З Діви воплотився,
Як дитина пеленами:
Вбогими повився.

Ангели співають,
Христа величають,
Пастухи у Вифлеємі
Новину звіщають.

Просим Тебе Царю,
Просим, Божий Сину:
Прийми й нашу Тобі славу
За дивну Новину!
Нині радість стала','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:christian'', ''cat:kolyadky'', ''cat:narodni'', ''Церковні пісні'', ''Пісні на християнську тематику'', ''Колядки'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_551508'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_551508','Нині радість стала','Нині радість стала,
