INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_551545','Ось і осінь золотава','Слова: невідомий, Анатолій Присяжнюк','uk','ukraine_1991',NULL,NULL,'Зі збірки "Ці невигадливі, зворушливі слова… (переклади з російської лірики ХІХ-ХХ ст.)" © А.А.Присяжнюк, переклад, 2007. A.Pris@i.ua',NULL,'Ось і осінь золотава.
В парку я старім броджу.
Чи минуле я гортаю,
А чи листя ворушу...

Розійшлися ми, розстались ...
Ну чому, чому так сталось,
Звідки впала ця некликана біда?
У моїй душі тривожно,
До усього звикнуть можна,
До розлуки ж, до розлуки
Ні, не звикнути - шкода.

Вже не чути птаства мову,
Листя музика тихіш.
Чи почати все ізнову,
Чи забути все скоріш?
Лазурові гаснуть далі...
Так вже сталось - ми розстались...
Звідки впала ця некликана біда?

На моїй душі тривожно,
До усього звикнуть можна,
До розлуки ж, до розлуки,
Ні, не звикнути - шкода.','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_551545'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_551545','Ось і осінь золотава','Ось і осінь золотава.
