INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5526405','Я вдячний вам','Музика: Сергій Нехаєвський Слова: Микола Савка. Виконує: Сергій Нехаєвський','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Безмежно вдячний всім вам, друзі!
І Богу вдячний, що ви є,
Що кожен з вас в життєвій смузі
Додав для мене щось своє.
Бо кожен вніс у мої мрі
Веселки кольори й тепло,
Am   H7           Em\C
Щоб я у кожній своїй дії
Робив ще краще, ніж було.
Життя то б''є, то обіймає...
І доля вносить щось своє.
Та це не страшно, бо я знаю,
Що в мене друзі й рідні є!
Я щиро вдячний моїм рідним!
Без їх підтримки - то пітьма.
Багаті теж бувають бідні,
Якщо рідні у них нема.
Я став багатий не грошима,
А тим, що в мене всі ви є!
Am    H7        Em\C
І я від кожного отримав
Тепло сердець в життя моє!
Я щиро вдячний всім вам, друзі!
Ви поряд, коли біль і щем,
Коли волошки квітнуть в лузі,
В мороз, у спеку й під дощем.
Ви поряд, коли біль і щем...','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5526405'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5526405','Я вдячний вам','Безмежно вдячний всім вам, друзі!
І Богу вдячний, що ви є,
Що кожен з вас в життєвій смузі
Додав для мене щось своє.
Бо кожен вніс у мої мрі
Веселки кольори й тепло,
Am   H7           Em\C
Щоб я у кожній своїй дії
Робив ще краще, ніж було.
Життя то б''є, то обіймає...
І доля вносить щось своє.
Та це не страшно, бо я знаю,
Що в мене друзі й рідні є!
Я щиро вдячний моїм рідним!
Без їх підтримки - то пітьма.
Багаті теж бувають бідні,
Якщо рідні у них нема.
Я став багатий не грошима,
А тим, що в мене всі ви є!
Am    H7        Em\C
І я від кожного отримав
Тепло сердець в життя моє!
Я щиро вдячний всім вам, друзі!
Ви поряд, коли біль і щем,
Коли волошки квітнуть в лузі,
В мороз, у спеку й під дощем.
Ви поряд, коли біль і щем...');
