INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5525508','Сину','Музика: МОРРІС, Максим Малик Слова: МОРРІС, Victor Yablonskiy. Виконує: Віталій Козловський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Куди тікають хвилини?..
А з ними і роки, як життя уроки...
Скажу про все, сину,
Коли свої зробиш ти дорослі кроки.
Я все життя мріяв
Побачити твої свої карі очі,
Нехай любов гріє,
Дарує нам спокій, тихі дні і ночі...
Прошу, небо, збережи його
Біля серця мого!..

Приспів:
Тихого cну, сину,
Де незнайома тобі втома.
Тихого сну, сину,
Нехай війна буде невідома!..
Цю неземну силу нам, сину,
Дарує Бог!..
Тихого сну, сину...
Спи, засинай,
Бо ти є вдома, вдома!..
Спи, засинай,
Бо ти є вдома, вдома!..
Спи, засинай,
Бо ти є вдома!..

Коли тримаю за руки,
Збивається подих та сковує рухи...
Що вище любові?..
І це так правдиво, бо ти - моє диво!..
Подякую долі,
Моїй половині, за нашу родину!..
Життя не чекає
Та все пробачає, дарує надію!..
Прошу, небо, збережи його
Біля серця мого!..

Приспів.','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5525508'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5525508','Сину','Куди тікають хвилини?..
