INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5534242','Українська коляда','Музика: Fajna Слова: Fajna','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Різдвяная зірка
Зійшла непомітно
І весь поміняла світ!
Печалі немає,
І ворог зникає,
І наш розквітає рід!
У єдності ми сильні,
Завжди маємо бути вільні!

Приспів:
Заспіває вся Земля! -
Українська коляда
Лунає на цілий світ,
Щоб цей Новий рік
Перемогу нам приніс
І щастя у кожен дім!

В родинному колі
У власному домі
Стрічаємо Новий Рік!
Міцні у нас руки,
Розірвемо пута,
Про нас ще почує світ!
У єдності ми сильні,
Завжди маємо бути вільні!

Приспів.

Добрий вечір тобі,
Пане господарю, радуйся!
Ой, радуйся, земле!
Син Божий народився!

Приспів. (2)

І щастя у кожен дім!
І щастя у кожен дім!','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:shchedrivky'', ''cat:suchasni-pisni-rizdvo'', ''Колядки'', ''Щедрівки'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5534242'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5534242','Українська коляда','Різдвяная зірка
Зійшла непомітно
