INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5534545','Різдво',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Час гортає сторінки,
Знову прийшло Різдво!
Сяють радістю лиця,
В серці й душі добро!
Син Божий світу дарований —
Святої ласки любов!
Нашому світу Спасіння,
Божа милість знов!

Приспів:
о! Різдво! -
Час хвалити Творця!
Бог і нині,
Як раніше, творить дива!
О! Різдво! -
Час довіряти Йому!
І відкрить серце своє
Творцю!

Боже благословення —
Сила любові з небес
Нас збереже й допоможе
Шлях наш пройти увесь!
Щастя і миру бажають
Друзі для вас щодня,
І від душі вас вітають
В цей день Різдва Христа!

Приспів.

Час гортає сторінки,
Знову прийшло Різдво!
Сяють радістю лиця,
На серці й душі тепло!

Приспів.

І відкрить серце своє
Творцю!','[''pisni.org.ua'', ''cat:suchasni-pisni-rizdvo'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5534545'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5534545','Різдво','Час гортає сторінки,
Знову прийшло Різдво!
Сяють радістю лиця,
В серці й душі добро!
Син Божий світу дарований —
Святої ласки любов!
Нашому світу Спасіння,
Божа милість знов!

Приспів:
о! Різдво! -
Час хвалити Творця!
Бог і нині,
Як раніше, творить дива!
О! Різдво! -
Час довіряти Йому!
І відкрить серце своє
Творцю!

Боже благословення —
Сила любові з небес
Нас збереже й допоможе
Шлях наш пройти увесь!
Щастя і миру бажають
Друзі для вас щодня,
І від душі вас вітають
В цей день Різдва Христа!

Приспів.

Час гортає сторінки,
Знову прийшло Різдво!
Сяють радістю лиця,
На серці й душі тепло!

Приспів.

І відкрить серце своє
Творцю!');
