INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_55343','Рідна мова','Музика: Павло Дворський Слова: Григорій Вієру. Виконує: Павло Дворський','uk','ukraine_1991',NULL,NULL,'Пісенник "Червона Рута". Київ: "Музична Україна" 1993',NULL,'Одною мовою одвік
Всі люди плачуть.
Одною мовою сміється
Всенький світ.
Та як любов і гнів
Улити в спів гарячий?
Лиш рідна мова дасть тобі
На те одвіт.

Приспів:
Коли ж уже не плачеш ти
І не смієшся,
Оглухнув серцем,
Не радієш, не болиш,
Тоді з землею наодинці зостаєшся, | (2)
Знов мовою одною, рідною мовчиш.   |

Одною мовою смієшся
І плачеш мовою одною,
Коли дитя вві сні
Ім''я твоє назве.
Та сум чи радість
Згасиш за наказом
Лиш мови рідної,
Що у душі живе.

Приспів.

Одною мовою одвік
Всі люди плачуть.
Одною мовою сміється
Всенький світ.
Та як любов і гнів
Улити в спів гарячий, -
Лиш рідна мова дасть тобі | (2)
На те отвіт.              |','[''pisni.org.ua'', ''cat:pisni-pro-movy'', ''Пісні про рідну мову'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_55343'), datetime('now')),datetime('now'));
