INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5536900','Серця',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'У небі зорі сяють ясно,
Тепло розтоплює лід сердець.
На землю зійшла любов небесна,
Дарована нам Творцем.

Приспів:
З''єднаймо серця, розпалімо вогонь,
Щоб горів він у кожному домі.
Любов''ю єдиною світ наповняй,
Це Різдво - це час для нас!

Народження дарує світло надії,
В очах дітей відблискує рай.
Відкрий своє серце для брата, сестри,
І Господь серед нас буде завжди.

Приспів.

Одна любов здатна змінити світ,
З''єднаймо мости, зітри біль та гнів.
Спільним піснеспівом славимо Царя,
Любов - це Його дар.

Приспів.

У небі зорі сяють ясно,
Це свято живе в наших серцях!
Різдво - час єдності й любові!','[''pisni.org.ua'', ''cat:suchasni-pisni-rizdvo'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5536900'), datetime('now')),datetime('now'));
