INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5508','Десь за Дніпром гримить гроза','Музика: Анатолій Сухий Слова: Анатолій Сухий. Виконує: Рутенія','uk','ukr_ssr_1919_1991',NULL,'1989','http://www.ukrmusic.com.ua/ukr/text.php?albumid=319&id=4307','Акорди записано на слух з аудіо. Тональність оригінальна. * Варіант з 1989 року: "Іди зустрінь свого Івана" ** В аудіо тут, можливо, інакше: "А Ви, мамо, своїх синів, моїх братів". Підбір акордів: bohdanko (pisni.org.ua)','Мотив 1:
Десь за Дніпром гримить гроза.
Стоїть під вишнею козак.
Стоїть, чекає,   милу гука_ є,
А мила спить,   не розбудить.
Мотив 2:
Проснись, проснись, моя кохана,
Вернулась сотня вже з боїв.
Іди зустрінь свого Степана,*
А ти, мамо, своїх сині_ ів,  моїх братів.**
Вернулись хлопці вже з походу,
Коли зацвів на дворі май.
Подай же їм з криниці воду
І вишитий рушник подай, і хліб розкрай.
Ще спить потомлене село,
На дворі ще не розсвіло.
І тихо-тихо понад ставом          |
Козаки йдуть, коней ведуть.       | (2)
Акорди у тональності "Hm"
(для середнього голосу):
Мотив 1:
Десь за Дніпром гримить гроза.
Стоїть під вишнею козак.
Стоїть, чекає,   милу гука_ є,
