INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5535405','Ще не вмерла Україна','Музика: Михайло Вербицький Слова: Павло Чубинський. Виконує: Хорея Козацька','uk','ukraine_1991',NULL,NULL,'записи виконання Хореї Козацької',NULL,'Ще не вмерла Україна і слава, і воля,
Ще нам, браття-козаки, усміхнеться доля!
Згинуть наші воріженьки, як роса на сонці,
Запануєм, браття миле, у своїй сторонці!

Приспів:
Душу, тіло ми положим за свою свободу    |
І покажем, що ми браття козацького роду! | (2)

Ой, Богдане, ой, Богдане, славний наш гетьмане,
Нащо віддав Україну москалям поганим?!!
Щоб вернути її честь станем куринями,
Назовемся України вірними синами!

Приспів.

Спам''ятаймо страшний час, лихую годину
Й тих, що вміли умірять за нашу Вкраїну!
Спам''ятаймо славну смерть лицарства-козацтва,
Щоб не втратить марно нам свойого юнацтва!

Приспів.','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5535405'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5535405','Ще не вмерла Україна','Ще не вмерла Україна і слава, і воля,
Ще нам, браття-козаки, усміхнеться доля!
Згинуть наші воріженьки, як роса на сонці,
Запануєм, браття миле, у своїй сторонці!

Приспів:
Душу, тіло ми положим за свою свободу    |
І покажем, що ми браття козацького роду! | (2)

Ой, Богдане, ой, Богдане, славний наш гетьмане,
Нащо віддав Україну москалям поганим?!!
Щоб вернути її честь станем куринями,
Назовемся України вірними синами!

Приспів.

Спам''ятаймо страшний час, лихую годину
Й тих, що вміли умірять за нашу Вкраїну!
Спам''ятаймо славну смерть лицарства-козацтва,
Щоб не втратить марно нам свойого юнацтва!

Приспів.');
