INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5534209','Різдво прийшло!','Музика: Христина Калень Слова: Христина Калень, Марія Паламар','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Різдво прийшло! | (4)

Різдво прийшло! -
Справжній Дарунок із Небес.
Різдво прийшло до нас!
