INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5542302','Квіти для мами','Музика: Володимир Будейчук Слова: Катерина Костюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Розцвіли весно мамині тюльпани,
Так чарує погляд їх червоний цвіт...
А в моєму серці квіти всі для мами,
І краса - такої ще не бачив світ!..
Розквітає влітку мамина лаванда,
Ароматом ніжно обіймає двір...
А в моєму серці квіти всі для мами,
Мерехтять для неї яскравіше зір!..

Приспів:
Квіти для мами не в''януть з роками,    |
Свій колір з любові ці квіти беруть!.. |
Квіти для мами не в''януть з роками,    |
І в серці моєму навіки цвітуть!..      | (2)

Заблукала осінь в хризантемах мами,
Кольоровим цвітом замела сліди...
А в моєму серці днями і ночами
Найріднішій мамі все буде цвісти!..
Взимку розквітають в мами орхідеї,
Нам тепло дарують у холодні дні!..
А в моєму серці квіти лиш для неї -
Кращої моєї мами на землі!..

Приспів. (2)

Квіти для мами не в''януть з роками,
І в серці моєму навіки цвітуть!..','[''pisni.org.ua'', ''cat:zahalni-cinnosti'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5542302'), datetime('now')),datetime('now'));
