INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5536949','Далека ніч Христового Різдва','Музика: Tanya Navrotski, Микола Василечко Слова: Mariya Zvirid','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Вона не в силі відвести очей -
В її колінах спить Спаситель світу.
Сам Бог зійшов на землю до людей,
Душа Марії Господу відкрита.
Величність неба він змінив на хлів,
І сяючий престол - на бідні ясла.
Спів ангелів на шепіт пастухів,
Його зоря в ту ніч горіла ясно.

Приспів:
Далека ніч Христового Різдва
Для мене стала радісним світанком.
Душі моїй спасіння принесла
І чистоту небесного серпанку!

Я вірю, як Марія, в простоті,
Схиляю серце все перед Тобою,
Нехай мій спів зіллється в висоті
Із ангельською дивною хвалою.

Приспів.

Христос прийшов заради мене в світ,
Він народився в бідності суворій,
Щоб виконати Божий заповіт,
Щоби до серця прихилити зорі!

Приспів.','[''pisni.org.ua'', ''cat:suchasni-pisni-rizdvo'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5536949'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5536949','Далека ніч Христового Різдва','Вона не в силі відвести очей -
