INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5542601','Блакить твоїх очей','Музика: Pivovarov Production Слова: Володимир Сосюра, Артем Пивоваров','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Між нами ґрат нема,
Та ними і не можна
Троянду й солов''я
Навіки розлучить...
Завжди в моїй душі
Сіяє непреложно
Очей твоїх блакить...
Для вірного чуття
Ніяких ґрат нема!..

І в білім шумі дня,
І в тьмі сумних ночей ти,
Куди б я не пішов,
Завжди в мені сія
Блакить твоїх очей!..
Блакить твоїх очей!..

О так, зі мною ти,
Ти назавжди зі мною!..
Як ти в журбі своїй,
Я мрією крилат,
І сльози я роню,
Схилившись над тобою...
Нема!..
Між нами ґрат немає!..
Завжди зі мною ти!..
Розлука — це омана...
Чи літо, чи зима,
Між нами ґрат нема!..','[''pisni.org.ua'', ''cat:devoted'', ''cat:zahalni-cinnosti'', ''Пісні присвячені окремим особам'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5542601'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5542601','Блакить твоїх очей','Між нами ґрат нема,
