INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5548003','Разом','Музика: Ірина Федишин Слова: Віталій Човник, Ірина Федишин','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Вирушає колона,
Ключі у замках,
Ці автівки —
Допомога у боях!
Кожен, хто поруч,
Творить дива,
Волонтерство —
Це сила жива!

Приспів:
Ми можемо здолати усе,
Якщо разом! Якщо разом!
Наша сила в серці живе,
Бо ми разом! Ми разом!

Там, де темно,
Засвітиться світло!
Там, де важко,
З''явиться шлях!
Хто, як не ми,
Плече підставляє —
ЗСУ допомагає!

Приспів.

Хтось зігріє
Добром і молитвою,
Хтось віддасть
Своєю працю і час.
Хтось нагодує,
Хтось дім відкриє —
Разом ми сила!
Ми змінимо час!

Приспів.','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5548003'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5548003','Разом','Вирушає колона,
Ключі у замках,
