INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5544444','Грушка','Музика: Ірина Вихованець (Fiinka) Слова: Ірина Вихованець (Fiinka)','uk','ukraine_1991',NULL,NULL,'аудіозапис','FIЇNKA: "Грушка" - гуцульський стародавній похоронний обряд. Це ігри й веселощі біля покійника, які робилиси для того, аби відвернути увагу від смерти в домі і розігнати тугу. Моя ж Грушка не про смерть, а навпаки про святкування життя. За основу я взяла знову ж таки гуцульську філософію. Мені си здає, шо се найвища міра сприйняттє невідворотного - з радістю. Набуваймоси сим життєм. А єк всьо скінчитси - зробимо "Грушку".','Гріх...
Вулицєма попри хату біг,
А ми пустили його на поріг,
І він у нашім домі си розліг,
Та й назбиравси цілий міх.
І єк тепер не розв''єзати йго?
А я питаюси себе: Чого?
Чого шукати десь в життю взірець,
Єкшо всьому прийде кінець?
Йой, нагрішім! Шоб було в чім каятись.
Йой, поспішім! Шоб доста пожити.
Кілько в життю враз є з чого маятись.
Лиш би, лиш би, лиш би вспіти любити!

Приспів:
За мою, за мою душу        |
Я жити по правді мушу,     |
За мою, за грішну душку... |
А єк всьо скінчитси,       |
Зробіт мені "Грушку".      | (2)

Світ...
На чім зійшовси і на чім стоїт?
Переплисти б його увесь убрід,
Аби лиш за собов лишити слід.
Єк просто всьо тепер звучит...
Коли ти знаєш, шо є основне,
Коли жиєш без всєких "нє" й "але",
Коли всі плещут в руки "молодець",
Але всьому прийде кінець!
Йой, нагрішім! Шоб було в чім каятись.
Йой, поспішім! Шоб доста пожити.
Кілько в життю враз є з чого маятись.
Лиш би, лиш би, лиш би вспіти любити!
Але жити так хочеси,
Єк останню годину!
Та й нашо ж мене та й Пан Біг
Сотворив єк людину?
Я не знаю, єк треба,
Мені б лиш си набути...
Якас моцна потреба
Собов в світі цім бути!..

Приспів.','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5544444'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5544444','Грушка','Гріх...
Вулицєма попри хату біг,
А ми пустили його на поріг,
І він у нашім домі си розліг,
Та й назбиравси цілий міх.
І єк тепер не розв''єзати йго?
А я питаюси себе: Чого?
Чого шукати десь в життю взірець,
Єкшо всьому прийде кінець?
Йой, нагрішім! Шоб було в чім каятись.
Йой, поспішім! Шоб доста пожити.
Кілько в життю враз є з чого маятись.
Лиш би, лиш би, лиш би вспіти любити!

Приспів:
За мою, за мою душу        |
Я жити по правді мушу,     |
За мою, за грішну душку... |
А єк всьо скінчитси,       |
Зробіт мені "Грушку".      | (2)

Світ...
На чім зійшовси і на чім стоїт?
Переплисти б його увесь убрід,
Аби лиш за собов лишити слід.
Єк просто всьо тепер звучит...
Коли ти знаєш, шо є основне,
Коли жиєш без всєких "нє" й "але",
Коли всі плещут в руки "молодець",
Але всьому прийде кінець!
Йой, нагрішім! Шоб було в чім каятись.
Йой, поспішім! Шоб доста пожити.
Кілько в життю враз є з чого маятись.
Лиш би, лиш би, лиш би вспіти любити!
Але жити так хочеси,
Єк останню годину!
Та й нашо ж мене та й Пан Біг
Сотворив єк людину?
Я не знаю, єк треба,
Мені б лиш си набути...
Якас моцна потреба
Собов в світі цім бути!..

Приспів.');
