INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5573209','Прийшло Різдво!','Музика: Мар''яна Яромій (Yaromiya) Слова: Мар''яна Яромій (Yaromiya)','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Світло, радість в кожнім домі,
Ангел ходить над селом.
Тиха ніч несе нам спокій
І молитву за столом...
Сніг кружляє над землею,
Хай радіє вся сім''я.
Бо приходить світло з неба
І у серці ожива!

Приспів:
Чути дзвони, серце грає,
І співають небеса!
Над землею зірка сяє,
Колядує все земля:
Танцюймо разом, прийшло Різдво!
Хай світло в серці живе давно!
Хай коляда летить крізь сни!
Без холодів різдвяні сни!
Танцюймо разом - співають всі!

Тиха ніч накрила місто,
Усмішки звучать давно,
Хай живе добро у домі,
Мир у серці і любов!
Сніг кружляє над землею,
Хай радіє вся сім''я.
Бо приходить світло з неба
І у серці ожива!

Приспів.','[''pisni.org.ua'', ''cat:suchasni-pisni-rizdvo'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5573209'), datetime('now')),datetime('now'));
