INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5567508','Слава, слава Чудотворцю!','(Святий Миколай іде). Музика: Олександр Соколов Слова: Зоя Ружин','uk','ukraine_1991',NULL,NULL,'авторське подання (Олександр Соколов)','Пісню виконує Світлана Пасека.','Ой, де ж Миколай забарився?
Білий сніг навкруги заіскрився.
Усі свята Миколая чекають,
У Зими і в Морозенка очі сяють!
Ой, іди до нас, Чудотворцю,
Вознесемо любов Батьку-Сонцю!
Все довкола у красі розквітає.
Бог-Отець на свято нас благословляє!

Приспів:
Слава! Слава Чудотворцю навіки!
Із небесних джерел віри ріки...
А серця у любові крилаті,
Вся земля на божественнім святі!

Мов зоря вдалині заясніла,
Йде святий Миколай - добра сила.
Щоб були ми доленосно багаті,
Він несе премудрість нам у благодаті!
Ой, всі Чудотворцю раділи!
Дари щедрі святково яріли...
Всі святого любов''ю вітаймо!
Новий рік із Чудотворцем зустрічаймо!

Приспів.

Слава, слава Чудотворцю! | (4)','[''pisni.org.ua'', ''cat:svyatyy-mykolay'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5567508'), datetime('now')),datetime('now'));
