INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5569343','Колишній','Музика: Max Barskih Слова: Max Barskih','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ти пішла, і все стоїть на місці,
Я хотів би мати другий шанс,
Та писати вже занадто пізно,
Сенсу вже нема...
Ти загубилась десь між чужих квартир,
Я відчуваю біль, коли бачу з ним,
І я дивлюсь як ти тонеш в його очах,
Ти вже не моя...

Приспів:
Тебе тримає хтось інший,
А я лишаюсь в тіні,
Тепер я - просто колишній,
І ти холодна, як лід...
Тебе кохає хтось інший,
A я вже сам по собі,
І моє серце не вірить,
Що ми з тобою чужі...

Ти щаслива? Можливо.
Не знаю, не лізу.
Я навчився не бути
Там, де мене нема...
Все добре! Серйозно!
Просто холодно трохи...
Я не тримаю зла...

Приспів.

Ти вже не моя,
Але все ще в мені...
Мене немає в твоїх вечорах,
А ти - в кожному з моїх!..

Приспів.','[''pisni.org.ua'', ''cat:zahalni-cinnosti'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5569343'), datetime('now')),datetime('now'));
