INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_560508','Щури','Музика: Тризубий Стас Слова: Тризубий Стас. Виконує: Тризубий Стас','uk','ukraine_1991',NULL,NULL,'http://www.itc.ua/forum/showthread.php?t=3075',NULL,'По хаті бігають щури,
Вилазять з кожної нори,
Вистрибують з підлоги,
Я прошу допомоги.
Нахабно вдерлися вони
У жовто-сині мої сни,
І всюди серед ночі
Червоні їхні очі.

Любить щур деревину гризти
І без того слабоньких стін,
Ще учора був комуністом,
Тепер у підпіллю він.

Колись у кожного щура
Була посада та нора
Велика чи маленька,
І він сидів тихенько.
Він в ту нору помалу гріб,
І буля нього мали хліб
І родичі і діти,
Чому б і не радіти.

Та нанесло грозу зненацька,
В очі блискавка, в серце грім,
Ой, ти горе, біда щуряцька,
Незвично смоктати хрін.

То поховалися щури
Лишень до певної пори,
Сидять в пивницях тиху,
Накликуючи лихо.
На слово суверенітет
В щуряків є імунітет,
Не діє і отрута,
Бо в них уся валюта.

А крім того сусід московський,
Найщуріший із всіх щурів,
Щур Щуринович Щуриновський
Боятися не велів.

І вже у кожного щура,
Нові повадки, як в кнура,
Потроху він звіріє,
Жиріє та нагліє.
І знову тягне догори
Свої криваві прапори,
І вся щуряча сила
Кричить на повне рило.

Браття щурики не ховайтесь,
Вилізайте з щилин та чур!
Всі щури всіх країн єднайтесь,
І смерть тому, хто не щур!

По хаті бігають щури,
Вилазять з кожної нори,
Вистрибують з підлоги,
Я прошу допомоги.
Бо вже не вночі, а зрання
Руденьке лисе щуриня
На мене щурить очі,
Знов щось сказати хоче...','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_560508'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_560508','Щури','По хаті бігають щури,
