INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_56242','Спомин про вчительку','Музика: Олександр Білаш Слова: Михайло Ткач','uk','ukraine_1991',NULL,NULL,'О.Білаш "Любисток" Київ "Музична Україна" 1970',NULL,'Мої літа несе на крилах час, -
За літом літо журавлиним клином, -
І світлий спомин, вчителько, про вас  |
У душу світить полум''ям калини.       | (2)

Приспів:
Матір дала мені мову,
Ви ж мені мрію дали,
Пісню мою колискову ранкову
Слухають, слухають в небі орли.

Ви, наче та далека світ-зоря,
Мене по світу повели світанням,
Понад степи, і гори, і моря           |
Благословився шлях мій сподіванням.   | (2)

Приспів.

До вас вертаю пройдені путі
І серце знову трепетно стукоче:
Чи так живу, чи так люблю в житті, -  |
Стаю на іспит перед ваші очі.         | (2)

Приспів.

Я знаю, вам не треба каяття,
Та все ж даруйте за гіркоти долі,
Якщо не вірив в добрі напуття,        |
Якщо завдав колись хоч трохи болю.    | (2)

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_56242'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_56242','Спомин про вчительку','Мої літа несе на крилах час, -
За літом літо журавлиним клином, -
І світлий спомин, вчителько, про вас  |
